// // This module implements a 4-to-1 multiplexer that selects between two possible program counter outputs based on a 2-bit select signal (PCSrc). When PCSrc is 0, the output PCout is set to the value of PC4; when PCSrc is 1, it selects PC4_imm; and for PCSrc values of 2 or higher, it outputs the jump address.
module top_module(
    input [31:0] PC4, PC4_imm, jump,
    input [1:0] PCSrc,
    output reg [31:0] PCout
    );always @(PC4 or PC4_imm or jump or PCSrc) begin
        if (PCSrc == 0) PCout = PC4;
        else if (PCSrc == 1) PCout = PC4_imm;
        else PCout = jump;
    end
endmodule
